# OEIS sequence: A393012

from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, prevprime, nextprime
def A393012_gen(): # generator of terms if the first n terms are desired.
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        for p in ps:
            if p == 5 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        mp = m*nextprime(max(ps.keys(),default=3))
        if mp not in hset:
            heappush(h,mp)
            hset.add(mp)
A393012_list = list(islice(A393012_gen(),40)) # _Chai Wah Wu_, Mar 31 2026

